module multi_8bit(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [15:0] partial_product [7:0];
    reg [7:0] shift_reg [7:0];
    reg [3:0] i, j;

    always @(*) begin
        // Initialize partial products and shift registers
        for (i = 0; i < 8; i = i + 1) begin
            partial_product[i] = 16'b0;
            shift_reg[i] = B;
        end

        // Generate partial products
        for (i = 0; i < 8; i = i + 1) begin
            if (shift_reg[i][0]) begin
                partial_product[i] = {8'b0, A} << i;
            end
            shift_reg[i] = shift_reg[i] >> 1;
        end

        // Accumulate partial products
        product = 16'b0;
        for (i = 0; i < 8; i = i + 1) begin
            product = product + partial_product[i];
        end
    end

endmodule
